<section class="admin-page-head"><div><p class="eyebrow">FINANCIAR</p><h1>Facturi și arhivă</h1></div><a class="admin-button secondary" href="<?= e(url('/admin/facturare')) ?>">Overview</a></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><section class="admin-panel"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Factură</th><th>Comandă</th><th>Client</th><th>Tip</th><th>Status</th><th>Data</th><th>Total</th></tr></thead><tbody><?php foreach($items as $item): ?><tr><td><a href="<?= e(url('/admin/facturi/'.$item['id'])) ?>"><strong><?= e($item['number']?:'#'.$item['id']) ?></strong></a></td><td><?= e($item['order_number']?:'—') ?></td><td><?= e($item['email']?:'—') ?></td><td><?= e($item['document_type']) ?></td><td><span class="status-pill <?= $item['status']==='issued'?'success':'' ?>"><?= e($item['status']) ?></span></td><td><?= $item['issue_date']?date('d.m.Y',strtotime($item['issue_date'])):'—' ?></td><td><?= money($item['grand_total_minor']) ?></td></tr><?php endforeach; ?></tbody></table></div></section>
